  chartsSection: {
    eyebrow: '― Charts & Settings ―',
    title: 'Field checks and construction starting points',
    description: 'These are practical construction starting references and daily-use reminders, not substitutes for engineered plans, stamped documents, or site-specific procedures. Use them to make better field decisions faster.',
  },
  processStartingPoints: [
    { title: 'Daily Site Readiness', description: 'Field work moves better when access, material, crew direction, and current documents are aligned before tools come out.', details: ['Confirm the active drawing set and site instructions before work starts.', 'Verify access, staging, and equipment paths before the crew commits to the area.', 'Check that material, hardware, and support gear are actually where the work is happening.', 'Treat readiness as part of production, not as office prep that ends before the shift begins.'] },
    { title: 'Layout Verification Start Point', description: 'Small layout misses become expensive quickly once embeds, anchors, openings, or supports start going in.', details: ['Confirm control points before marking production locations.', 'Use one dimension language across the crew when possible.', 'Check early benchmark points before committing a full run.', 'If the field condition does not match the plan, stop and verify before adapting by habit.'] },
    { title: 'Access and Fall-Exposure Control', description: 'A fast-moving site still needs disciplined access setup and real hazard control instead of informal workarounds.', details: ['Verify ladders, platforms, lifts, and temporary access before use.', 'Keep the travel path clear for both workers and material movement.', 'Tie hazard controls to the actual task, location, and exposure instead of relying on generic paperwork.', 'If the crew is improvising access, the planning is already behind.'] },
    { title: 'Trade Handoff Discipline', description: 'Many site problems show up at the boundary between trades rather than inside one crew alone.', details: ['Confirm what is complete, what is protected, and what is still pending before turnover.', 'Use visible status updates instead of relying on memory or verbal assumptions.', 'Document field changes before the next trade builds on them.', 'If repeat clashes happen, inspect the handoff system first.'] },
    { title: 'Material Staging Control', description: 'Good field flow depends on putting the right material in the right area before the crew loses time hunting for it.', details: ['Stage material by sequence of installation, not by easiest drop-off point.', 'Keep critical hardware and specialty items physically tied to the work package.', 'Protect staged material from damage, weather, and other trades.', 'If crews keep walking for parts, the staging plan is weak.'] },
    { title: 'Punch and Rework Prevention', description: 'Many punch-list items were visible earlier but nobody stopped to capture them while the crew still owned the work area.', details: ['Build quick verification into the work before turnover.', 'Do not leave final inspection logic entirely to the end of the project.', 'Close visible defects while access and tools are still available.', 'If the same misses repeat, update the field checklist instead of blaming memory.'] },
  ],
