  practicesSection: {
    eyebrow: '― Best Practices ―',
    title: 'Construction habits that usually separate clean field execution from repeat field friction',
    description: 'Good construction performance depends on more than manpower and hustle. These are the kinds of operating disciplines that keep drawings, material, layout, access, and trade handoffs aligned.',
  },
  bestPractices: [
    { title: 'Drawing and revision control', points: ['Field crews should know exactly which drawing set and sketch direction is active.', 'A fast site still breaks down when revisions move slower than the work.', 'If repeated field changes happen, inspect the document flow first.'] },
    { title: 'Access and workface planning', points: ['Weak access planning becomes lost time and avoidable risk quickly.', 'Treat ladders, lifts, routes, staging, and material flow as part of the work plan, not an afterthought.', 'If crews keep improvising access, the plan is incomplete.'] },
    { title: 'Trade coordination and turnover', points: ['Many site problems happen at the handoff between crews, not inside one scope alone.', 'Use visible status and clear boundaries so downstream work is not built on assumptions.', 'If the same clash repeats, the coordination system needs work.'] },
    { title: 'Field verification before commitment', points: ['Do not let the crew scale up a layout or install pattern before the first checks are proven.', 'Early verification costs less than late correction.', 'If a condition looks off, stop and prove it before adapting the whole run.'] },
    { title: 'Material control on site', points: ['Staged material should match the sequence of work, not just the easiest delivery point.', 'Protect critical hardware, anchors, and finish-sensitive items before they disappear into jobsite noise.', 'If crews keep hunting for parts, the material-control system is too weak.'] },
    { title: 'Punch-list prevention', points: ['A large share of punch work was visible earlier but never captured while the crew still owned the area.', 'Build short verification steps into the work before turnover.', 'If the same misses recur, improve the field checklist instead of relying on memory.'] },
  ],
